const jwt = require('jsonwebtoken');

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';
const ALLOWED_ALGORITHMS = ['HS256', 'HS384', 'HS512'];

const authMiddleware = (options = {}) => {
  const {
    secret = JWT_SECRET,
    algorithms = ALLOWED_ALGORITHMS,
    requireClaims = ['exp', 'iat', 'sub'],
    tokenExtractor = extractTokenFromHeader,
    clockTolerance = 0
  } = options;

  return (req, res, next) => {
    try {
      const token = tokenExtractor(req);
      
      if (!token) {
        return res.status(401).json({
          error: 'Authentication required',
          message: 'No token provided'
        });
      }

      const decoded = jwt.verify(token, secret, {
        algorithms: algorithms,
        clockTolerance: clockTolerance,
        complete: false
      });

      for (const claim of requireClaims) {
        if (!(claim in decoded)) {
          return res.status(401).json({
            error: 'Invalid token',
            message: `Missing required claim: ${claim}`
          });
        }
      }

      req.user = {
        id: decoded.sub,
        email: decoded.email,
        role: decoded.role,
        ...decoded
      };

      next();
    } catch (error) {
      if (error.name === 'TokenExpiredError') {
        return res.status(401).json({
          error: 'Token expired',
          message: 'Your session has expired. Please login again.'
        });
      }
      
      if (error.name === 'JsonWebTokenError') {
        return res.status(401).json({
          error: 'Invalid token',
          message: 'Token verification failed'
        });
      }

      if (error.name === 'NotBeforeError') {
        return res.status(401).json({
          error: 'Token not active',
          message: 'Token is not yet valid'
        });
      }

      return res.status(500).json({
        error: 'Authentication error',
        message: 'An error occurred during authentication'
      });
    }
  };
};

function extractTokenFromHeader(req) {
  const authHeader = req.headers.authorization;
  
  if (!authHeader) {
    return null;
  }

  const parts = authHeader.split(' ');
  
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return null;
  }

  return parts[1];
}

const optionalAuth = (options = {}) => {
  const {
    secret = JWT_SECRET,
    algorithms = ALLOWED_ALGORITHMS,
    tokenExtractor = extractTokenFromHeader
  } = options;

  return (req, res, next) => {
    try {
      const token = tokenExtractor(req);
      
      if (!token) {
        req.user = null;
        return next();
      }

      const decoded = jwt.verify(token, secret, {
        algorithms: algorithms,
        complete: false
      });

      req.user = {
        id: decoded.sub,
        email: decoded.email,
        role: decoded.role,
        ...decoded
      };

      next();
    } catch (error) {
      req.user = null;
      next();
    }
  };
};

const requireRole = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({
        error: 'Authentication required',
        message: 'You must be logged in to access this resource'
      });
    }

    if (!req.user.role || !allowedRoles.includes(req.user.role)) {
      return res.status(403).json({
        error: 'Forbidden',
        message: 'You do not have permission to access this resource'
      });
    }

    next();
  };
};

const generateToken = (payload, options = {}) => {
  const {
    secret = JWT_SECRET,
    expiresIn = '24h',
    algorithm = 'HS256'
  } = options;

  if (!ALLOWED_ALGORITHMS.includes(algorithm)) {
    throw new Error(`Algorithm ${algorithm} is not allowed`);
  }

  const tokenPayload = {
    sub: payload.userId || payload.id,
    email: payload.email,
    role: payload.role,
    ...payload
  };

  return jwt.sign(tokenPayload, secret, {
    algorithm: algorithm,
    expiresIn: expiresIn,
    issuer: payload.issuer || 'your-app-name',
    audience: payload.audience || 'your-app-users'
  });
};

const refreshToken = (token, options = {}) => {
  const {
    secret = JWT_SECRET,
    algorithms = ALLOWED_ALGORITHMS,
    expiresIn = '24h'
  } = options;

  try {
    const decoded = jwt.verify(token, secret, {
      algorithms: algorithms,
      ignoreExpiration: true
    });

    const now = Math.floor(Date.now() / 1000);
    const gracePeriod = 7 * 24 * 60 * 60;

    if (decoded.exp && (now - decoded.exp) > gracePeriod) {
      throw new Error('Token is too old to refresh');
    }

    delete decoded.iat;
    delete decoded.exp;
    delete decoded.nbf;

    return jwt.sign(decoded, secret, {
      algorithm: algorithms[0],
      expiresIn: expiresIn
    });
  } catch (error) {
    throw error;
  }
};

